// assets
import { Layers, MonitorSmartphone, Puzzle } from "lucide-react";

// constants
const featureData = [
  {
    title: "Responsive",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    icon: MonitorSmartphone,
    iconColor: "text-blue-500"
  },
  {
    title: "Creative Design",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    icon: Puzzle,
    iconColor: "text-yellow-500"
  },
  {
    title: "Quick Result",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    icon: Layers,
    iconColor: "text-green-500"
  }
];

//  ------------------------------ | FEATURE - 7 | ------------------------------  //

export default function Feature7() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header Section */}
        <div className="mx-auto max-w-2xl text-center mb-16 lg:mb-24">
          <h2 className="mb-6">Provided Features</h2>
          <p className="text-muted-foreground text-lg">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Features Grid */}
        <div className="grid grid-cols-12 gap-6">
          {featureData.map((item, index) => (
            <div
              key={index}
              className="col-span-12 md:col-span-4 flex flex-col items-center text-center gap-6"
            >
              <div className={`mb-2 ${item.iconColor}`}>
                <item.icon size={40} strokeWidth={1.5} />
              </div>
              <h5 className="mb-2">{item.title}</h5>
              <p className="text-muted-foreground max-w-xs">
                {item.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
